def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if item == 0 and capacity >= 0:
            base_score = 0
            for n in range(1, 5):
                base_score += ((-1) ** n) / (n + 1)
            priorities[i] = base_score
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                factor = (ratio ** (k + 2)) / (k * (k + 1))
                if k % 2 == 0:
                    penalty -= factor
                else:
                    penalty += factor
            priorities[i] = (ratio ** 4) + abs(penalty) * 3
        elif 1 < ratio <= 2:
            score = 0
            for p in range(1, 8):
                sign = 1 if p % 3 == 0 else -1
                term = sign * (ratio ** (p / 2)) / (p)
                score += term
            multiplier = 20 if ratio > 1.5 else 12
            priorities[i] = abs(score) * multiplier
            extra_boost = 0
            for q in range(1, 5):
                extra_boost += (ratio ** q) / (q * 3)
            priorities[i] += extra_boost
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 7):
                sign = (-1) ** (j + 1)
                term = sign * (ratio ** (j * 0.75)) / (j ** 1.5)
                score += term
            if ratio < 0.25:
                multiplier = 18
            elif ratio < 0.5:
                multiplier = 11
            elif ratio < 0.75:
                multiplier = 7
            else:
                multiplier = 4
            priorities[i] = abs(score) * multiplier
            if ratio > 0.7:
                extra = 0
                for m in range(1, 5):
                    divisor = m * (m + 2)
                    extra += (ratio ** (m/2)) / divisor
                priorities[i] += extra * 2
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) + 5
        if capacity > 100 and ratio <= 1:
            priorities[i] *= 0.7
    return priorities
